# Bounded Label Tracker - Prevents Cardinality Explosion
# =============================================================================

class BoundedLabelTracker:
    """
    Thread-safe tracker that bounds the number of unique label combinations.
    Uses LRU eviction and TTL to prevent unbounded growth.
    """
    
    def __init__(self, max_size: int, ttl: int = 3600):
        self._max_size = max_size
        self._ttl = ttl
        self._lock = threading.Lock()
        self._entries: OrderedDict[str, float] = OrderedDict()
        self._overflow_count = 0
    
    def try_track(self, key: str) -> bool:
        """
        Attempt to track a label combination.
        Returns True if the combination is allowed, False if rejected.
        """
        now = time.time()
        
        with self._lock:
            # If already tracked, update timestamp and allow
            if key in self._entries:
                self._entries.move_to_end(key)
                self._entries[key] = now
                return True
            
            # Evict expired entries first
            self._evict_expired(now)
            
            # Check if we have room
            if len(self._entries) >= self._max_size:
                self._overflow_count += 1
                return False
            
            # Track new combination
            self._entries[key] = now
            return True
    
    def _evict_expired(self, now: float):
        """Remove entries older than TTL."""
        expired_keys = []
        for key, timestamp in self._entries.items():
            if now - timestamp > self._ttl:
                expired_keys.append(key)
            else:
                break  # OrderedDict is ordered by insertion/access
        
        for key in expired_keys:
            del self._entries[key]
    
    @property
    def size(self) -> int:
        with self._lock:
            return len(self._entries)
    
    @property
    def overflow_count(self) -> int:
        with self._lock:
            return self._overflow_count


class BoundedSet:
    """Thread-safe bounded set for tracking unique values."""
    
    def __init__(self, max_size: int):
        self._max_size = max_size
        self._lock = threading.Lock()
        self._items: OrderedDict[str, float] = OrderedDict()
    
    def try_add(self, item: str) -> str:
        """
        Try to add an item. If the set is full and item is new,
        returns '__overflow__' sentinel value.
        """
        with self._lock:
            if item in self._items:
                self._items.move_to_end(item)
                self._items[item] = time.time()
                return item
            
            if len(self._items) >= self._max_size:
                return '__overflow__'
            
            self._items[item] = time.time()
            return item


