# Path Sanitizer - Normalizes and validates paths
# =============================================================================

class PathSanitizer:
    """Sanitizes and normalizes request paths to reduce cardinality."""
    
    def __init__(self, config: CardinalityConfig):
        self._config = config
        self._path_cache: dict[str, str] = {}
        self._cache_lock = threading.Lock()
        self._max_cache_size = 10000
    
    def sanitize(self, path: str) -> str:
        """
        Sanitize a request path:
        1. Normalize dynamic segments
        2. Validate against allowlist
        3. Truncate excessive depth
        4. Cache results
        """
        # Check cache first
        with self._cache_lock:
            if path in self._path_cache:
                return self._path_cache[path]
        
        sanitized = self._do_sanitize(path)
        
        # Cache the result (bounded)
        with self._cache_lock:
            if len(self._path_cache) < self._max_cache_size:
                self._path_cache[path] = sanitized
        
        return sanitized
    
    def _do_sanitize(self, path: str) -> str:
        # Strip query parameters (should already be done, but be safe)
        path = path.split('?')[0]
        
        # Normalize trailing slashes
        path = path.rstrip('/') or '/'
        
        # Apply normalization patterns to replace dynamic segments
        for pattern, replacement in self._config.PATH_NORMALIZATION_PATTERNS:
            path = pattern.sub(replacement, path)
        
        # Limit path depth to prevent deep path cardinality
        parts = path.split('/')
        if len(parts) > 6:
            path = '/'.join(parts[:6]) + '/...'
        
        # Limit total path length
        if len(path) > 200:
            path = path[:200] + '...'
        
        # Validate against allowlist if configured
        if self._config.ALLOWED_PATH_PREFIXES:
            if not any(path.startswith(prefix) for prefix in self._config.ALLOWED_PATH_PREFIXES):
                if path not in ('/', '/health', '/metrics'):
                    path = '/__unmatched__'
        
        return path


# =============================================================================
# User/Session ID Sanitizer
# =============================================================================

class IdentitySanitizer:
    """
    Sanitizes user and session IDs.
    Optionally hashes them for privacy while maintaining uniqueness.
    """
    
    @staticmethod
    def sanitize_user_id(user_id: str, hash_ids: bool = False) -> str:
        if not user_id:
            return '__anonymous__'
        
        # Validate format - only allow expected characters
        if not re.match(r'^[a-zA-Z0-9_\-\.@]{1,128}$', user_id):
            return '__invalid_user__'
        
        if hash_ids:
            return 'user_' + hashlib.sha256(user_id.encode()).hexdigest()[:16]
        
        return user_id
    
    @staticmethod
    def sanitize_session_id(session_id: str, hash_ids: bool = False) -> str:
        if not session_id:
            return '__no_session__'
        
        # Validate format
        if not re.match(r'^[a-zA-Z0-9_\-]{1,128}$', session_id):
            return '__invalid_session__'
        
        if hash_ids:
            return 'sess_' + hashlib.sha256(session_id.encode()).hexdigest()[:16]
        
        return session_id


