app = Flask(__name__)
metrics = ProtectedMetrics()


def extract_user_id() -> str:
    """Extract user ID from request (from header, token, etc.)."""
    # Check various sources for user identification
    user_id = request.headers.get('X-User-ID')
    if not user_id:
        user_id = request.args.get('user_id')
    if not user_id:
        # Could also extract from JWT token, session, etc.
        user_id = request.headers.get('X-Forwarded-User')
    return user_id


def extract_session_id() -> str:
    """Extract session ID from request."""
    session_id = request.headers.get('X-Session-ID')
    if not session_id:
        session_id = request.cookies.get('session_id')
    return session_id


@app.before_request
def before_request():
    """Record request start time and extract identity."""
    g.start_time = time.time()
    g.user_id = extract_user_id()
    g.session_id = extract_session_id()


@app.after_request
def after_request(response):
    """Record metrics after each request."""
    # Skip metrics endpoint itself to avoid recursion
    if request.path == '/metrics':
        return response
    
    duration = time.time() - g.get('start_time', time.time())
    
    request_size = request.content_length or 0
    response_size = response.content_length or 0
    
    metrics.record_request(
        method=request.method,
        raw_path=request.path,
        status_code=response.status_code,
        duration=duration,
        user_id=g.get('user_id'),
        session_id=g.get('session_id'),
        request_size=request_size,
        response_size=response_size,
    )
    
    return response


