# Decorator for custom per-endpoint metrics
# =============================================================================

def track_user_path_metric(metric_name: str):
    """
    Decorator to create and track a custom metric for specific endpoints.
    Uses the same cardinality protection.
    """
    def decorator(f):
        counter = Counter(
            f'{metric_name}_total',
            f'Custom counter for {metric_name}',
            ['user_id', 'path'],
        )
        
        @wraps(f)
        def wrapper(*args, **kwargs):
            user_id = extract_user_id() or '__anonymous__'
            sanitized_user = metrics.identity_sanitizer.sanitize_user_id(user_id)
            sanitized_path = metrics.path_sanitizer.sanitize(request.path)
            
            tracked_user = metrics.user_tracker.try_add(sanitized_user)
            tracked_path = metrics.path_tracker.try_add(sanitized_path)
            
            if tracked_user != '__overflow__' and tracked_path != '__overflow__':
                counter.labels(
                    user_id=tracked_user,
                    path=tracked_path,
                ).inc()
            
            return f(*args, **kwargs)
        
        return wrapper
    return decorator


@app.route('/api/search')
@track_user_path_metric('search_requests')
def search():
    """Example: Search endpoint with custom metric tracking."""
    query = request.args.get('q', '')
    return {'query': query, 'results': []}


